import { mkdirSync, writeFileSync } from 'node:fs';
import {
  aboutPage,
  articles,
  contributorRoles,
  contributors,
  events,
  jobs,
  siteSettings,
} from './baseline-data.mjs';
import { renderInsert, sqlJson, sqlString } from './sql-utils.mjs';

const outputPath = 'infra/directus/sql/002_seed.sql';

function withSort(items) {
  return items.map((item, index) => ({
    ...item,
    sort: index + 1,
  }));
}

const sql = [
  '-- Generated by scripts/directus/render-seed-sql.mjs',
  'begin;',
  '',
  'delete from public.site_settings;',
  'delete from public.about_page;',
  'delete from public.articles;',
  'delete from public.jobs;',
  'delete from public.events;',
  'delete from public.contributor_roles;',
  'delete from public.contributors;',
  '',
  renderInsert({
    table: 'public.site_settings',
    columns: [
      'id',
      'site_name',
      'tagline',
      'description',
      'primary_domain',
      'secondary_domain',
      'media_domain',
      'hero_title',
      'hero_summary',
      'hero_primary_cta_label',
      'hero_primary_cta_url',
      'hero_secondary_cta_label',
      'hero_secondary_cta_url',
      'social_links',
      'footer_groups',
      'home_stats',
      'copyright_text',
      'date_updated',
    ],
    rows: [
      {
        id: String(siteSettings.id),
        site_name: sqlString(siteSettings.site_name),
        tagline: sqlString(siteSettings.tagline),
        description: sqlString(siteSettings.description),
        primary_domain: sqlString(siteSettings.primary_domain),
        secondary_domain: sqlString(siteSettings.secondary_domain),
        media_domain: sqlString(siteSettings.media_domain),
        hero_title: sqlString(siteSettings.hero_title),
        hero_summary: sqlString(siteSettings.hero_summary),
        hero_primary_cta_label: sqlString(siteSettings.hero_primary_cta_label),
        hero_primary_cta_url: sqlString(siteSettings.hero_primary_cta_url),
        hero_secondary_cta_label: sqlString(siteSettings.hero_secondary_cta_label),
        hero_secondary_cta_url: sqlString(siteSettings.hero_secondary_cta_url),
        social_links: sqlJson(siteSettings.social_links),
        footer_groups: sqlJson(siteSettings.footer_groups),
        home_stats: sqlJson(siteSettings.home_stats),
        copyright_text: sqlString(siteSettings.copyright_text),
        date_updated: sqlString('2026-04-05T10:00:00.000Z'),
      },
    ],
    onConflict: 'on conflict do nothing',
  }),
  '',
  renderInsert({
    table: 'public.about_page',
    columns: ['id', 'title', 'summary', 'sections', 'date_updated'],
    rows: [
      {
        id: String(aboutPage.id),
        title: sqlString(aboutPage.title),
        summary: sqlString(aboutPage.summary),
        sections: sqlJson(aboutPage.sections),
        date_updated: sqlString('2026-04-05T10:00:00.000Z'),
      },
    ],
    onConflict: 'on conflict do nothing',
  }),
  '',
  renderInsert({
    table: 'public.articles',
    columns: [
      'status',
      'sort',
      'date_created',
      'date_updated',
      'slug',
      'title',
      'summary',
      'body',
      'published_at',
      'reading_time',
      'authors',
      'tags',
      'cover_image_url',
      'cover_accent',
    ],
    rows: withSort(articles).map((article) => ({
      status: sqlString(article.status),
      sort: String(article.sort),
      date_created: sqlString(article.published_at),
      date_updated: sqlString(article.published_at),
      slug: sqlString(article.slug),
      title: sqlString(article.title),
      summary: sqlString(article.summary),
      body: sqlString(article.body),
      published_at: sqlString(article.published_at),
      reading_time: sqlString(article.reading_time),
      authors: sqlJson(article.authors),
      tags: sqlJson(article.tags),
      cover_image_url: sqlString(article.cover_image_url),
      cover_accent: sqlString(article.cover_accent),
    })),
    onConflict: 'on conflict do nothing',
  }),
  '',
  renderInsert({
    table: 'public.jobs',
    columns: [
      'status',
      'sort',
      'date_created',
      'date_updated',
      'slug',
      'company_name',
      'role_title',
      'salary',
      'supports_remote',
      'work_mode',
      'location',
      'summary',
      'description',
      'responsibilities',
      'apply_url',
      'apply_note',
      'contact_label',
      'contact_value',
      'published_at',
      'expires_at',
      'tags',
    ],
    rows: withSort(jobs).map((job) => ({
      status: sqlString(job.status),
      sort: String(job.sort),
      date_created: sqlString(job.published_at),
      date_updated: sqlString(job.published_at),
      slug: sqlString(job.slug),
      company_name: sqlString(job.company_name),
      role_title: sqlString(job.role_title),
      salary: sqlString(job.salary),
      supports_remote: job.supports_remote ? 'true' : 'false',
      work_mode: sqlString(job.work_mode),
      location: sqlString(job.location),
      summary: sqlString(job.summary),
      description: sqlString(job.description),
      responsibilities: sqlJson(job.responsibilities),
      apply_url: sqlString(job.apply_url),
      apply_note: sqlString(job.apply_note),
      contact_label: sqlString(job.contact_label),
      contact_value: sqlString(job.contact_value),
      published_at: sqlString(job.published_at),
      expires_at: sqlString(job.expires_at),
      tags: sqlJson(job.tags),
    })),
    onConflict: 'on conflict do nothing',
  }),
  '',
  renderInsert({
    table: 'public.events',
    columns: [
      'status',
      'event_status',
      'sort',
      'date_created',
      'date_updated',
      'slug',
      'title',
      'summary',
      'content',
      'start_at',
      'end_at',
      'location',
      'venue',
      'city',
      'registration_url',
      'registration_note',
      'cover_image_url',
      'tags',
    ],
    rows: withSort(events).map((event) => ({
      status: sqlString(event.status),
      event_status: sqlString(event.event_status),
      sort: String(event.sort),
      date_created: sqlString(event.start_at),
      date_updated: sqlString(event.start_at),
      slug: sqlString(event.slug),
      title: sqlString(event.title),
      summary: sqlString(event.summary),
      content: sqlString(event.content),
      start_at: sqlString(event.start_at),
      end_at: sqlString(event.end_at),
      location: sqlString(event.location),
      venue: sqlString(event.venue),
      city: sqlString(event.city),
      registration_url: sqlString(event.registration_url),
      registration_note: sqlString(event.registration_note),
      cover_image_url: sqlString(event.cover_image_url),
      tags: sqlJson(event.tags),
    })),
    onConflict: 'on conflict do nothing',
  }),
  '',
  renderInsert({
    table: 'public.contributor_roles',
    columns: ['status', 'sort', 'date_created', 'date_updated', 'slug', 'name', 'description'],
    rows: withSort(contributorRoles).map((role) => ({
      status: sqlString(role.status),
      sort: String(role.sort),
      date_created: sqlString('2026-04-05T10:00:00.000Z'),
      date_updated: sqlString('2026-04-05T10:00:00.000Z'),
      slug: sqlString(role.slug),
      name: sqlString(role.name),
      description: sqlString(role.description),
    })),
    onConflict: 'on conflict do nothing',
  }),
  '',
  renderInsert({
    table: 'public.contributors',
    columns: [
      'status',
      'sort',
      'date_created',
      'date_updated',
      'slug',
      'name',
      'avatar_url',
      'avatar_seed',
      'headline',
      'bio',
      'role_slugs',
      'twitter_url',
      'wechat',
      'telegram',
    ],
    rows: withSort(contributors).map((contributor) => ({
      status: sqlString(contributor.status),
      sort: String(contributor.sort),
      date_created: sqlString('2026-04-05T10:00:00.000Z'),
      date_updated: sqlString('2026-04-05T10:00:00.000Z'),
      slug: sqlString(contributor.slug),
      name: sqlString(contributor.name),
      avatar_url: sqlString(contributor.avatar_url),
      avatar_seed: sqlString(contributor.avatar_seed),
      headline: sqlString(contributor.headline),
      bio: sqlString(contributor.bio),
      role_slugs: sqlJson(contributor.role_slugs),
      twitter_url: sqlString(contributor.twitter_url),
      wechat: sqlString(contributor.wechat),
      telegram: sqlString(contributor.telegram),
    })),
    onConflict: 'on conflict do nothing',
  }),
  '',
  'commit;',
  '',
].join('\n');

mkdirSync('infra/directus/sql', { recursive: true });
writeFileSync(outputPath, `${sql.trim()}\n`);
console.log(`wrote ${outputPath}`);
